      ...prev,
      schools: prev.schools.map(s => s.id === schoolId ? { ...s, status: s.status === 'Active' ? 'Suspended' : 'Active' } : s),
      notifications: [{ id: Date.now(), message: `[Super Admin changed subscription] ${state.schools.find(s => s.id === schoolId).name} is now ${state.schools.find(s => s.id === schoolId).status === 'Active' ? 'Suspended' : 'Active'}.`, channels: ['Admin', 'Accountant'], time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) }, ...prev.notifications]
    }));
  };

  return panelWrapper('Manage Subscriptions', 'Data view displaying active school plan tiers with suspend/activate toggles.', (
    <div className="table-card">
      <table>
        <thead>
          <tr><th>School ID</th><th>School Name</th><th>Plan Tier</th><th>Status</th><th>Action</th></tr>
