function ViewTotalStudents({ state }) {
  const total = state.students.length;
  const byGrade = state.students.reduce((acc, student) => {
    acc[student.grade] = (acc[student.grade] || 0) + 1;
    return acc;
  }, {});

  return panelWrapper('View Total Students', 'Metric breakdown displaying an aggregated count of all students across the platform.', (
    <div className="metrics-grid">
      <div className="metric-card"><div>Total Students</div><div>{total}</div></div>
      {Object.entries(byGrade).map(([grade, count]) => (
        <div key={grade} className="metric-card"><div>Grade {grade}</div><div>{count}</div></div>
      ))}
    </div>
  ));
}

function ViewTotalTeachers({ state }) {
  const total = state.teachers.length;
  const subjectCounts = state.teachers.reduce((acc, teacher) => {
    teacher.subjects.forEach(subject => { acc[subject] = (acc[subject] || 0) + 1; });
    return acc;
  }, {});

  return panelWrapper('View Total Teachers', 'High-level metric visualization displaying total system staff counts.', (
    <div className="metrics-grid">
      <div className="metric-card"><div>Total Teachers</div><div>{total}</div></div>
      {Object.entries(subjectCounts).map(([subject, count]) => (
        <div key={subject} className="metric-card"><div>{subject}</div><div>{count}</div></div>
      ))}
    </div>
  ));
}

