function ApproveAdmissions({ state, setState }) {
  const approve = (admissionNumber) => {
    const admission = state.pendingAdmissions.find(item => item.admissionNumber === admissionNumber);
    if (!admission) return;
    const newStudent = { admissionNumber: admission.admissionNumber, name: admission.name, grade: admission.grade, section: admission.section, parent: { name: admission.parent, contact: 'Not Available' }, attendance: { present: 0, absent: 0, late: 0 }, marks: {}, status: 'Active' };
    setState(prev => ({ ...prev, students: [...prev.students, newStudent], pendingAdmissions: prev.pendingAdmissions.filter(item => item.admissionNumber !== admissionNumber), notifications: [{ id: Date.now(), message: '[Principal approved admission] New student onboarded.', channels: ['Admin', 'Parent', 'Accountant'], time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) }, ...prev.notifications] }));
  };
  const reject = (admissionNumber) => {
    setState(prev => ({ ...prev, pendingAdmissions: prev.pendingAdmissions.filter(item => item.admissionNumber !== admissionNumber), notifications: [{ id: Date.now(), message: '[Principal rejected admission] Admission application declined.', channels: ['Parent'], time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) }, ...prev.notifications] }));
  };

  return panelWrapper('Approve Admissions', 'A workflow grid displaying incoming student profiles with approve/reject triggers.', (
    <div className="table-card">
      <table>
        <thead><tr><th>Admission No.</th><th>Student</th><th>Grade / Section</th><th>Parent</th><th>Actions</th></tr></thead>
        <tbody>
          {state.pendingAdmissions.map(admission => (
