      <div className="table-card">
        <table>
          <thead><tr><th>Student</th><th>Fee Type</th><th>Amount</th><th>Due Date</th><th>Status</th></tr></thead>
          <tbody>{pendingFees.map(fee => (
            <tr key={fee.id} className={fee.id === selectedFeeId ? 'selected-row' : ''}>
