              <td>₹{fee.amount.toLocaleString()}</td>
              <td>{fee.dueDate}</td>
              <td>{fee.status}</td>
              <td><button type="button" onClick={() => setSelectedFeeId(fee.id)}>Select</button></td>
            </tr>
          ))}</tbody>
        </table>
      </div>
